+    fn clear_visual_selection(&mut self) {
+        self.visual_selection = None;
+    }
+
+    fn start_visual_selection(&mut self, kind: VisualKind, right_content: &str) {
+        let pane = self.focus;
+        let lines = self.pane_lines(pane, right_content);
+        let position = self.visual_start_position(pane, &lines);
+        self.visual_selection = Some(VisualSelection {
+            pane,
+            kind,
+            anchor: position,
+            active: position,
+        });
+        self.mode = UiMode::Command;
+    }
+
+    fn handle_visual_key(&mut self, key: UiKey, right_content: &str) -> Vec<UiAction> {
+        match key {
+            UiKey::Esc => {
+                self.clear_visual_selection();
+                Vec::new()
+            }
+            UiKey::Char('h') | UiKey::Left => {
+                self.move_visual_selection(0, -1, right_content);
+                Vec::new()
+            }
+            UiKey::Char('j') | UiKey::Down => {
+                self.move_visual_selection(1, 0, right_content);
+                Vec::new()
+            }
+            UiKey::Char('k') | UiKey::Up => {
+                self.move_visual_selection(-1, 0, right_content);
+                Vec::new()
+            }
+            UiKey::Char('l') | UiKey::Right => {
+                self.move_visual_selection(0, 1, right_content);
+                Vec::new()
+            }
+            UiKey::Char('v') => {
+                self.set_visual_kind(VisualKind::Character);
+                Vec::new()
+            }
+            UiKey::Char('V') => {
+                self.set_visual_kind(VisualKind::Line);
+                Vec::new()
+            }
+            UiKey::CtrlV => {
+                self.set_visual_kind(VisualKind::Block);
+                Vec::new()
+            }
+            UiKey::Char('y') => {
+                self.yank_visual_selection(right_content, None);
+                Vec::new()
+            }
+            UiKey::Char('Y') => {
+                self.yank_visual_selection(right_content, Some(VisualKind::Line));
+                Vec::new()
+            }
+            _ => Vec::new(),
+        }
+    }
+
+    fn set_visual_kind(&mut self, kind: VisualKind) {
+        if let Some(selection) = self.visual_selection.as_mut() {
+            selection.kind = kind;
+        }
+    }
+
+    fn move_visual_selection(&mut self, row_delta: isize, column_delta: isize, right_content: &str) {
+        let Some(selection) = self.visual_selection else {
+            return;
+        };
+        let lines = self.pane_lines(selection.pane, right_content);
+        let max_row = lines.len().saturating_sub(1);
+        let row = selection
+            .active
+            .row
+            .saturating_add_signed(row_delta)
+            .min(max_row);
+        let max_column = lines
+            .get(row)
+            .map(|line| line.text.chars().count().saturating_sub(1))
+            .unwrap_or(0);
+        let column = selection
+            .active
+            .column
+            .saturating_add_signed(column_delta)
+            .min(max_column);
+        if let Some(selection) = self.visual_selection.as_mut() {
+            selection.active = VisualPosition { row, column };
+        }
+    }
+
+    fn yank_visual_selection(&mut self, right_content: &str, kind_override: Option<VisualKind>) {
+        let text = self.selected_visual_text(right_content, kind_override);
+        self.clipboard_text = Some(text);
+        self.pending_clipboard.set(true);
+        let copied_chars = self
+            .clipboard_text
+            .as_deref()
+            .map(|text| text.chars().count())
+            .unwrap_or(0);
+        self.clear_visual_selection();
+        self.show_status_notice(
+            format!("copied {copied_chars} chars"),
+            Duration::from_secs(STATUS_NOTICE_SECONDS),
+        );
+    }
+
+    fn selected_visual_text(&self, right_content: &str, kind_override: Option<VisualKind>) -> String {
+        let Some(selection) = self.visual_selection else {
+            return String::new();
+        };
+        let kind = kind_override.unwrap_or(selection.kind);
+        let lines = self.pane_lines(selection.pane, right_content);
+        if lines.is_empty() {
+            return String::new();
+        }
+        match kind {
+            VisualKind::Character => selected_character_text(selection, &lines),
+            VisualKind::Line => selected_line_text(selection, &lines),
+            VisualKind::Block => selected_block_text(selection, &lines),
+        }
+    }
+
+    fn visual_start_position(&self, pane: PaneFocus, lines: &[PaneLine]) -> VisualPosition {
+        let max_row = lines.len().saturating_sub(1);
+        let row = match pane {
+            PaneFocus::Left => self.control_selected,
+            PaneFocus::Right => max_row,
+        }
+        .min(max_row);
+        VisualPosition { row, column: 0 }
+    }
+
+    fn visual_cursor_position(&self) -> Option<(u16, u16)> {
+        let selection = self.visual_selection?;
+        let row = selection.active.row.min(usize::from(u16::MAX)) as u16;
+        let column = selection.active.column.min(usize::from(u16::MAX)) as u16;
+        match selection.pane {
+            PaneFocus::Left => Some((row.saturating_add(2), column.saturating_add(2))),
+            PaneFocus::Right => {
+                let layout = self.layout();
+                Some((
+                    row.saturating_add(2),
+                    layout.left_width.saturating_add(2).saturating_add(column),
+                ))
+            }
+        }
+    }
+
+    fn pane_lines(&self, pane: PaneFocus, right_content: &str) -> Vec<PaneLine> {
+        match pane {
+            PaneFocus::Left => self.left_pane_lines(),
+            PaneFocus::Right => {
+                let mut lines = self
+                    .visible_right_content(right_content)
+                    .lines()
+                    .map(|line| PaneLine::new(line.to_string(), false))
+                    .collect::<Vec<_>>();
+                if lines.is_empty() {
+                    lines.push(PaneLine::new(String::new(), false));
+                }
+                lines
+            }
+        }
+    }
+
+    fn left_pane_lines(&self) -> Vec<PaneLine> {
+        let inner_width = usize::from(self.layout().left_width.saturating_sub(2).max(1));
+        let mut lines = vec![PaneLine::new(
+            if self.control_selected == 0 {
+                "> work-leaf  command"
+            } else {
+                "  work-leaf  command"
+            },
+            false,
+        )];
+        for (visible_position, agent_index) in self.visible_agent_indices().iter().enumerate() {
+            let agent = &self.agents[*agent_index];
+            let selected = self.control_selected == visible_position + 1;
+            lines.push(PaneLine::new(
+                compact_agent_row(agent, selected, inner_width),
+                agent.ready,
+            ));
+            if !agent.modified_files.is_empty() {
+                lines.push(PaneLine::new(
+                    format!(
+                        "    files: {}",
+                        agent
+                            .modified_files
+                            .iter()
+                            .map(|path| path.display().to_string())
+                            .collect::<Vec<_>>()
+                            .join(", ")
+                    ),
+                    false,
+                ));
+            }
+            for (label, agents) in [
+                ("conflicts", &agent.conflicting_agents),
+                ("depends-on", &agent.depends_on),
+                ("depended-on-by", &agent.depended_on_by),
+            ] {
+                if !agents.is_empty() {
+                    lines.push(PaneLine::new(
+                        format!(
+                            "    {label}: {}",
+                            agents
+                                .iter()
+                                .map(AgentId::as_str)
+                                .collect::<Vec<_>>()
+                                .join(", ")
+                        ),
+                        false,
+                    ));
+                }
+            }
+        }
+        lines
+    }
+
+    fn right_pane_spans(&self, right_content: &str) -> Vec<Spans<'static>> {
+        let mut spans = right_content
+            .lines()
+            .enumerate()
+            .map(|(row, line)| self.styled_line_spans(PaneFocus::Right, row, line))
+            .collect::<Vec<_>>();
+        if spans.is_empty() {
+            spans.push(Spans::from(Span::raw(String::new())));
+        }
+        spans
+    }
+
+    fn styled_line_spans(&self, pane: PaneFocus, row: usize, line: &str) -> Spans<'static> {
+        if self.visual_selection.is_none() || line.is_empty() {
+            return Spans::from(Span::raw(line.to_string()));
+        }
+
+        let mut spans = Vec::new();
+        let mut chunk = String::new();
+        let mut selected_chunk = None;
+        for (column, ch) in line.chars().enumerate() {
+            let selected = self.visual_selects_position(pane, row, column);
+            if selected_chunk.is_some_and(|current| current != selected) {
+                push_styled_chunk(&mut spans, &mut chunk, selected_chunk.unwrap_or(false));
+            }
+            selected_chunk = Some(selected);
+            chunk.push(ch);
+        }
+        push_styled_chunk(&mut spans, &mut chunk, selected_chunk.unwrap_or(false));
+        Spans::from(spans)
+    }
+
+    fn visual_selects_position(&self, pane: PaneFocus, row: usize, column: usize) -> bool {
+        let Some(selection) = self.visual_selection else {
+            return false;
+        };
+        if selection.pane != pane {
+            return false;
+        }
+        match selection.kind {
+            VisualKind::Character => character_selection_contains(selection, row, column),
+            VisualKind::Line => line_selection_contains(selection, row),
+            VisualKind::Block => block_selection_contains(selection, row, column),
+        }
+    }
