+fn push_styled_chunk(spans: &mut Vec<Span<'static>>, chunk: &mut String, selected: bool) {
+    if chunk.is_empty() {
+        return;
+    }
+    let text = std::mem::take(chunk);
+    if selected {
+        spans.push(Span::styled(
+            text,
+            Style::default().add_modifier(Modifier::REVERSED),
+        ));
+    } else {
+        spans.push(Span::raw(text));
+    }
+}
+
+fn character_selection_contains(selection: VisualSelection, row: usize, column: usize) -> bool {
+    let (start, end) = ordered_positions(selection.anchor, selection.active);
+    if row < start.row || row > end.row {
+        return false;
+    }
+    if start.row == end.row {
+        return row == start.row && column >= start.column && column <= end.column;
+    }
+    match row {
+        row if row == start.row => column >= start.column,
+        row if row == end.row => column <= end.column,
+        _ => true,
+    }
+}
+
+fn line_selection_contains(selection: VisualSelection, row: usize) -> bool {
+    let start = selection.anchor.row.min(selection.active.row);
+    let end = selection.anchor.row.max(selection.active.row);
+    row >= start && row <= end
+}
+
+fn block_selection_contains(selection: VisualSelection, row: usize, column: usize) -> bool {
+    let start_row = selection.anchor.row.min(selection.active.row);
+    let end_row = selection.anchor.row.max(selection.active.row);
+    let start_column = selection.anchor.column.min(selection.active.column);
+    let end_column = selection.anchor.column.max(selection.active.column);
+    row >= start_row && row <= end_row && column >= start_column && column <= end_column
+}
+
+fn selected_character_text(selection: VisualSelection, lines: &[PaneLine]) -> String {
+    let (start, end) = ordered_positions(selection.anchor, selection.active);
+    let max_row = lines.len().saturating_sub(1);
+    let start_row = start.row.min(max_row);
+    let end_row = end.row.min(max_row);
+    if start_row == end_row {
+        return slice_chars_inclusive(&lines[start_row].text, start.column, end.column);
+    }
+
+    let mut selected = Vec::new();
+    selected.push(slice_chars_from(&lines[start_row].text, start.column));
+    for line in lines.iter().take(end_row).skip(start_row + 1) {
+        selected.push(line.text.clone());
+    }
+    selected.push(slice_chars_to_inclusive(&lines[end_row].text, end.column));
+    selected.join("\n")
+}
+
+fn selected_line_text(selection: VisualSelection, lines: &[PaneLine]) -> String {
+    let max_row = lines.len().saturating_sub(1);
+    let start = selection.anchor.row.min(selection.active.row).min(max_row);
+    let end = selection.anchor.row.max(selection.active.row).min(max_row);
+    lines
+        .iter()
+        .take(end + 1)
+        .skip(start)
+        .map(|line| line.text.clone())
+        .collect::<Vec<_>>()
+        .join("\n")
+}
+
+fn selected_block_text(selection: VisualSelection, lines: &[PaneLine]) -> String {
+    let max_row = lines.len().saturating_sub(1);
+    let start_row = selection.anchor.row.min(selection.active.row).min(max_row);
+    let end_row = selection.anchor.row.max(selection.active.row).min(max_row);
+    let start_column = selection.anchor.column.min(selection.active.column);
+    let end_column = selection.anchor.column.max(selection.active.column);
+    lines
+        .iter()
+        .take(end_row + 1)
+        .skip(start_row)
+        .map(|line| slice_chars_inclusive(&line.text, start_column, end_column))
+        .collect::<Vec<_>>()
+        .join("\n")
+}
+
+fn ordered_positions(
+    left: VisualPosition,
+    right: VisualPosition,
+) -> (VisualPosition, VisualPosition) {
+    if left.row < right.row || (left.row == right.row && left.column <= right.column) {
+        (left, right)
+    } else {
+        (right, left)
+    }
+}
+
+fn slice_chars_from(text: &str, start: usize) -> String {
+    text.chars().skip(start).collect()
+}
+
+fn slice_chars_to_inclusive(text: &str, end: usize) -> String {
+    text.chars().take(end.saturating_add(1)).collect()
+}
+
+fn slice_chars_inclusive(text: &str, start: usize, end: usize) -> String {
+    if start > end {
+        return String::new();
+    }
+    text.chars()
+        .skip(start)
+        .take(end.saturating_sub(start).saturating_add(1))
+        .collect()
+}
+
+fn osc52_sequence(text: &str) -> String {
+    format!("\u{1b}]52;c;{}\u{7}", base64_encode(text.as_bytes()))
+}
+
+fn base64_encode(bytes: &[u8]) -> String {
+    const TABLE: &[u8; 64] =
+        b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
+    let mut output = String::new();
+    let mut index = 0;
+    while index < bytes.len() {
+        let first = bytes[index];
+        let second = bytes.get(index + 1).copied();
+        let third = bytes.get(index + 2).copied();
+
+        output.push(TABLE[(first >> 2) as usize] as char);
+        output.push(TABLE[(((first & 0b0000_0011) << 4) | second.unwrap_or(0) >> 4) as usize] as char);
+        if let Some(second) = second {
+            output.push(TABLE[(((second & 0b0000_1111) << 2) | third.unwrap_or(0) >> 6) as usize] as char);
+        } else {
+            output.push('=');
+        }
+        if let Some(third) = third {
+            output.push(TABLE[(third & 0b0011_1111) as usize] as char);
+        } else {
+            output.push('=');
+        }
+
+        index += 3;
+    }
+    output
+}
