+fn base64_encode(bytes: &[u8]) -> String {
+    const TABLE: &[u8; 64] =
+        b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
+    let mut output = String::new();
+    let mut index = 0;
+    while index < bytes.len() {
+        let first = bytes[index];
+        let second = bytes.get(index + 1).copied();
+        let third = bytes.get(index + 2).copied();
+        let second_index = ((first & 0b0000_0011) << 4) | (second.unwrap_or(0) >> 4);
+
+        output.push(TABLE[usize::from(first >> 2)] as char);
+        output.push(TABLE[usize::from(second_index)] as char);
+        if let Some(second) = second {
+            let third_index = ((second & 0b0000_1111) << 2) | (third.unwrap_or(0) >> 6);
+            output.push(TABLE[usize::from(third_index)] as char);
+        } else {
+            output.push('=');
+        }
+        if let Some(third) = third {
+            output.push(TABLE[usize::from(third & 0b0011_1111)] as char);
+        } else {
+            output.push('=');
+        }
+
+        index += 3;
+    }
+    output
+}
