+fn character_selection_contains(selection: VisualSelection, row: usize, column: usize) -> bool {
+    let (start, end) = ordered_positions(selection.anchor, selection.active);
+    if row < start.row || row > end.row {
+        return false;
+    }
+    if start.row == end.row {
+        return row == start.row && column >= start.column && column <= end.column;
+    }
+    match row {
+        row if row == start.row => column >= start.column,
+        row if row == end.row => column <= end.column,
+        _ => true,
+    }
+}
