+fn line_selection_contains(selection: VisualSelection, row: usize) -> bool {
+    let start = selection.anchor.row.min(selection.active.row);
+    let end = selection.anchor.row.max(selection.active.row);
+    row >= start && row <= end
+}
+
+fn block_selection_contains(selection: VisualSelection, row: usize, column: usize) -> bool {
+    let start_row = selection.anchor.row.min(selection.active.row);
+    let end_row = selection.anchor.row.max(selection.active.row);
+    let start_column = selection.anchor.column.min(selection.active.column);
+    let end_column = selection.anchor.column.max(selection.active.column);
+    row >= start_row && row <= end_row && column >= start_column && column <= end_column
+}
