+    controller
+        .send_message(&agent_id, "please adjust naming")
+        .unwrap();
+
+    assert!(controller.wait_for_idle(Duration::from_secs(1)));
+    let sends_after_reopen = backend.sends();
+    assert_eq!(sends_after_reopen.len(), sends_after_review.len() + 1);
